for target in $(cat target.txt);do mkdir -p OUT-WEB-BIRD/$target && cat OUT-WEB-BIRD/$target/$target-URL* | sort -u >> OUT-WEB-BIRD/$target/$target-URL-imput-katana && timeout 600 katana -list OUT-WEB-BIRD/$target/$target-URL-imput-katana -hl -jc -jsl -kf all -d 3 -c 8 -rl 10 -timeout 15 -retry 1 -no-incognito -ignore-query-params -jsonl -silent -o OUT-WEB-BIRD/$target/$target-katana.json ;done
